-- Starville Phase 6: approved repository content catalog and initial immutable publications.
-- Generated from the reviewed TypeScript seed manifests. No remote URLs or uploaded-file claims.

create extension if not exists pgcrypto with schema extensions;

create or replace function private.world_manifest_checksum(p_manifest jsonb)
returns text
language sql
immutable
security definer
set search_path = ''
as $$
  select encode(extensions.digest(convert_to(p_manifest::text, 'UTF8'), 'sha256'), 'hex');
$$;

revoke all on function private.world_manifest_checksum(jsonb)
  from public, anon, authenticated, service_role;

with asset_seed(asset_key, category) as (
  values
  ('cottage-amber', 'building'),
  ('cottage-sage', 'building'),
  ('tree-pine', 'tree'),
  ('tree-maple', 'tree'),
  ('rock-moss', 'rock'),
  ('fence-willow', 'fence'),
  ('lamp-star', 'lamp'),
  ('notice-board', 'sign'),
  ('flowers-moon', 'flower'),
  ('bush-round', 'decoration'),
  ('moonstone-marker', 'rock'),
  ('brooklight-sign', 'sign'),
  ('orchard-road-sign', 'sign'),
  ('whisperpine-gate', 'fence'),
  ('closed-route-marker', 'fence')
)
insert into public.world_assets (
  asset_key,
  content_hash,
  storage_path,
  source_type,
  media_type,
  width,
  height,
  file_size_bytes,
  approval_status,
  repository_owned,
  approved_at
)
select
  asset_key,
  encode(
    extensions.digest(convert_to('starville-procedural:v1:' || asset_key, 'UTF8'), 'sha256'),
    'hex'
  ),
  'repository/procedural/' || asset_key,
  'repository_procedural',
  'application/x-starville-procedural',
  null,
  null,
  null,
  'approved',
  true,
  now()
from asset_seed
on conflict (asset_key) do nothing;

