insert into public.world_maps (
  slug,
  display_name,
  description,
  status,
  default_spawn_id
)
select slug, display_name, description, 'active', default_spawn_id
from seed
on conflict (slug) do nothing;

with seed(slug, display_name, description, default_spawn_id, manifest) as (
  values
